import xmlschema
import requests


def validate(xml):
    schema = xmlschema.XMLSchema('http://www.sample-manifest.org/schemas/test.xsd')

    try:
        schema.validate(xml)

        return True
    except Exception as e:
        print("Validation Error: {}".format(e))

    return False

import sys

def main():
    try:
        input_file = open(sys.argv[1], 'r', encoding='utf8')
    except IndexError as e:
        print('Usage:\npython3 validate.py <filename>')

        raise SystemExit() from None
    
    for line in input_file:
        if validate(line):
            print('Valid XML')

if __name__ == '__main__': main()